1	use core::{fmt, mem};
2	
3	use crate::{
4	    atomic::{Pointable, Shared},
5	    collector::Collector,
6	    deferred::Deferred,
7	    internal::Local,
8	};
9	
10	/// A guard that keeps the current thread pinned.
11	///
12	/// # Pinning
13	///
14	/// The current thread is pinned by calling [`pin`], which returns a new guard:
15	///
16	/// ```
17	/// use crossbeam_epoch as epoch;
18	///
19	/// // It is often convenient to prefix a call to `pin` with a `&` in order to create a reference.
20	/// // This is not really necessary, but makes passing references to the guard a bit easier.
21	/// let guard = &epoch::pin();
22	/// ```
23	///
24	/// When a guard gets dropped, the current thread is automatically unpinned.
25	///
26	/// # Pointers on the stack
27	///
28	/// Having a guard allows us to create pointers on the stack to heap-allocated objects.
29	/// For example:
30	///
31	/// ```
32	/// use crossbeam_epoch::{self as epoch, Atomic};
33	/// use std::sync::atomic::Ordering::SeqCst;
34	///
35	/// // Create a heap-allocated number.
36	/// let a = Atomic::new(777);
37	///
38	/// // Pin the current thread.
39	/// let guard = &epoch::pin();
40	///
41	/// // Load the heap-allocated object and create pointer `p` on the stack.
42	/// let p = a.load(SeqCst, guard);
43	///
44	/// // Dereference the pointer and print the value:
45	/// if let Some(num) = unsafe { p.as_ref() } {
46	///     println!("The number is {}.", num);
47	/// }
48	/// # unsafe { drop(a.into_owned()); } // avoid leak
49	/// ```
50	///
51	/// # Multiple guards
52	///
53	/// Pinning is reentrant and it is perfectly legal to create multiple guards. In that case, the
54	/// thread will actually be pinned only when the first guard is created and unpinned when the last
55	/// one is dropped:
56	///
57	/// ```
58	/// use crossbeam_epoch as epoch;
59	///
60	/// let guard1 = epoch::pin();
61	/// let guard2 = epoch::pin();
62	/// assert!(epoch::is_pinned());
63	/// drop(guard1);
64	/// assert!(epoch::is_pinned());
65	/// drop(guard2);
66	/// assert!(!epoch::is_pinned());
67	/// ```
68	///
69	/// [`pin`]: super::pin
70	pub struct Guard {
71	    pub(crate) local: *const Local,
72	}
73	
74	impl Guard {
75	    /// Stores a function so that it can be executed at some point after all currently pinned
76	    /// threads get unpinned.
77	    ///
78	    /// This method first stores `f` into the thread-local (or handle-local) cache. If this cache
79	    /// becomes full, some functions are moved into the global cache. At the same time, some
80	    /// functions from both local and global caches may get executed in order to incrementally
81	    /// clean up the caches as they fill up.
82	    ///
83	    /// There is no guarantee when exactly `f` will be executed. The only guarantee is that it
84	    /// won't be executed until all currently pinned threads get unpinned. In theory, `f` might
85	    /// never run, but the epoch-based garbage collection will make an effort to execute it
86	    /// reasonably soon.
87	    ///
88	    /// If this method is called from an [`unprotected`] guard, the function will simply be
89	    /// executed immediately.
90	    pub fn defer<F, R>(&self, f: F)
91	    where
92	        F: FnOnce() -> R,
93	        F: Send + 'static,
94	    {
95	        unsafe {
96	            self.defer_unchecked(f);
97	        }
98	    }
99	
100	    /// Stores a function so that it can be executed at some point after all currently pinned
101	    /// threads get unpinned.
102	    ///
103	    /// This method first stores `f` into the thread-local (or handle-local) cache. If this cache
104	    /// becomes full, some functions are moved into the global cache. At the same time, some
105	    /// functions from both local and global caches may get executed in order to incrementally
106	    /// clean up the caches as they fill up.
107	    ///
108	    /// There is no guarantee when exactly `f` will be executed. The only guarantee is that it
109	    /// won't be executed until all currently pinned threads get unpinned. In theory, `f` might
110	    /// never run, but the epoch-based garbage collection will make an effort to execute it
111	    /// reasonably soon.
112	    ///
113	    /// If this method is called from an [`unprotected`] guard, the function will simply be
114	    /// executed immediately.
115	    ///
116	    /// # Safety
117	    ///
118	    /// The given function must not hold reference onto the stack. It is highly recommended that
119	    /// the passed function is **always** marked with `move` in order to prevent accidental
120	    /// borrows.
121	    ///
122	    /// ```
123	    /// use crossbeam_epoch as epoch;
124	    ///
125	    /// let guard = &epoch::pin();
126	    /// let message = "Hello!";
127	    /// unsafe {
128	    ///     // ALWAYS use `move` when sending a closure into `defer_unchecked`.
129	    ///     guard.defer_unchecked(move || {
130	    ///         println!("{}", message);
131	    ///     });
132	    /// }
133	    /// ```
134	    ///
135	    /// Apart from that, keep in mind that another thread may execute `f`, so anything accessed by
136	    /// the closure must be `Send`.
137	    ///
138	    /// We intentionally didn't require `F: Send`, because Rust's type systems usually cannot prove
139	    /// `F: Send` for typical use cases. For example, consider the following code snippet, which
140	    /// exemplifies the typical use case of deferring the deallocation of a shared reference:
141	    ///
142	    /// ```ignore
143	    /// let shared = Owned::new(7i32).into_shared(guard);
144	    /// guard.defer_unchecked(move || shared.into_owned()); // `Shared` is not `Send`!
145	    /// ```
146	    ///
147	    /// While `Shared` is not `Send`, it's safe for another thread to call the deferred function,
148	    /// because it's called only after the grace period and `shared` is no longer shared with other
149	    /// threads. But we don't expect type systems to prove this.
150	    ///
151	    /// # Examples
152	    ///
153	    /// When a heap-allocated object in a data structure becomes unreachable, it has to be
154	    /// deallocated. However, the current thread and other threads may be still holding references
155	    /// on the stack to that same object. Therefore it cannot be deallocated before those references
156	    /// get dropped. This method can defer deallocation until all those threads get unpinned and
157	    /// consequently drop all their references on the stack.
158	    ///
159	    /// ```
160	    /// use crossbeam_epoch::{self as epoch, Atomic, Owned};
161	    /// use std::sync::atomic::Ordering::SeqCst;
162	    ///
163	    /// let a = Atomic::new("foo");
164	    ///
165	    /// // Now suppose that `a` is shared among multiple threads and concurrently
166	    /// // accessed and modified...
167	    ///
168	    /// // Pin the current thread.
169	    /// let guard = &epoch::pin();
170	    ///
171	    /// // Steal the object currently stored in `a` and swap it with another one.
172	    /// let p = a.swap(Owned::new("bar").into_shared(guard), SeqCst, guard);
173	    ///
174	    /// if !p.is_null() {
175	    ///     // The object `p` is pointing to is now unreachable.
176	    ///     // Defer its deallocation until all currently pinned threads get unpinned.
177	    ///     unsafe {
178	    ///         // ALWAYS use `move` when sending a closure into `defer_unchecked`.
179	    ///         guard.defer_unchecked(move || {
180	    ///             println!("{} is now being deallocated.", p.deref());
181	    ///             // Now we have unique access to the object pointed to by `p` and can turn it
182	    ///             // into an `Owned`. Dropping the `Owned` will deallocate the object.
183	    ///             drop(p.into_owned());
184	    ///         });
185	    ///     }
186	    /// }
187	    /// # unsafe { drop(a.into_owned()); } // avoid leak
188	    /// ```
189	    pub unsafe fn defer_unchecked<F, R>(&self, f: F)
190	    where
191	        F: FnOnce() -> R,
192	    {
193	        unsafe {
194	            if let Some(local) = self.local.as_ref() {
195	                local.defer(Deferred::new(move || drop(f())), self);
196	            } else {
197	                drop(f());
198	            }
199	        }
200	    }
201	
202	    /// Stores a destructor for an object so that it can be deallocated and dropped at some point
203	    /// after all currently pinned threads get unpinned.
204	    ///
205	    /// This method first stores the destructor into the thread-local (or handle-local) cache. If
206	    /// this cache becomes full, some destructors are moved into the global cache. At the same
207	    /// time, some destructors from both local and global caches may get executed in order to
208	    /// incrementally clean up the caches as they fill up.
209	    ///
210	    /// There is no guarantee when exactly the destructor will be executed. The only guarantee is
211	    /// that it won't be executed until all currently pinned threads get unpinned. In theory, the
212	    /// destructor might never run, but the epoch-based garbage collection will make an effort to
213	    /// execute it reasonably soon.
214	    ///
215	    /// If this method is called from an [`unprotected`] guard, the destructor will simply be
216	    /// executed immediately.
217	    ///
218	    /// # Safety
219	    ///
220	    /// The object must not be reachable by other threads anymore, otherwise it might be still in
221	    /// use when the destructor runs.
222	    ///
223	    /// Apart from that, keep in mind that another thread may execute the destructor, so the object
224	    /// must be sendable to other threads.
225	    ///
226	    /// We intentionally didn't require `T: Send`, because Rust's type systems usually cannot prove
227	    /// `T: Send` for typical use cases. For example, consider the following code snippet, which
228	    /// exemplifies the typical use case of deferring the deallocation of a shared reference:
229	    ///
230	    /// ```ignore
231	    /// let shared = Owned::new(7i32).into_shared(guard);
232	    /// guard.defer_destroy(shared); // `Shared` is not `Send`!
233	    /// ```
234	    ///
235	    /// While `Shared` is not `Send`, it's safe for another thread to call the destructor, because
236	    /// it's called only after the grace period and `shared` is no longer shared with other
237	    /// threads. But we don't expect type systems to prove this.
238	    ///
239	    /// # Examples
240	    ///
241	    /// When a heap-allocated object in a data structure becomes unreachable, it has to be
242	    /// deallocated. However, the current thread and other threads may be still holding references
243	    /// on the stack to that same object. Therefore it cannot be deallocated before those references
244	    /// get dropped. This method can defer deallocation until all those threads get unpinned and
245	    /// consequently drop all their references on the stack.
246	    ///
247	    /// ```
248	    /// use crossbeam_epoch::{self as epoch, Atomic, Owned};
249	    /// use std::sync::atomic::Ordering::SeqCst;
250	    ///
251	    /// let a = Atomic::new("foo");
252	    ///
253	    /// // Now suppose that `a` is shared among multiple threads and concurrently
254	    /// // accessed and modified...
255	    ///
256	    /// // Pin the current thread.
257	    /// let guard = &epoch::pin();
258	    ///
259	    /// // Steal the object currently stored in `a` and swap it with another one.
260	    /// let p = a.swap(Owned::new("bar").into_shared(guard), SeqCst, guard);
261	    ///
262	    /// if !p.is_null() {
263	    ///     // The object `p` is pointing to is now unreachable.
264	    ///     // Defer its deallocation until all currently pinned threads get unpinned.
265	    ///     unsafe {
266	    ///         guard.defer_destroy(p);
267	    ///     }
268	    /// }
269	    /// # unsafe { drop(a.into_owned()); } // avoid leak
270	    /// ```
271	    pub unsafe fn defer_destroy<T: ?Sized + Pointable>(&self, ptr: Shared<'_, T>) {
272	        unsafe { self.defer_unchecked(move || ptr.into_owned()) }
273	    }
274	
275	    /// Clears up the thread-local cache of deferred functions by executing them or moving into the
276	    /// global cache.
277	    ///
278	    /// Call this method after deferring execution of a function if you want to get it executed as
279	    /// soon as possible. Flushing will make sure it is residing in the global cache, so that
280	    /// any thread has a chance of taking the function and executing it.
281	    ///
282	    /// If this method is called from an [`unprotected`] guard, it is a no-op (nothing happens).
283	    ///
284	    /// # Examples
285	    ///
286	    /// ```
287	    /// use crossbeam_epoch as epoch;
288	    ///
289	    /// let guard = &epoch::pin();
290	    /// guard.defer(move || {
291	    ///     println!("This better be printed as soon as possible!");
292	    /// });
293	    /// guard.flush();
294	    /// ```
295	    pub fn flush(&self) {
296	        if let Some(local) = unsafe { self.local.as_ref() } {
297	            local.flush(self);
298	        }
299	    }
300	
301	    /// Unpins and then immediately re-pins the thread.
302	    ///
303	    /// This method is useful when you don't want delay the advancement of the global epoch by
304	    /// holding an old epoch. For safety, you should not maintain any guard-based reference across
305	    /// the call (the latter is enforced by `&mut self`). The thread will only be repinned if this
306	    /// is the only active guard for the current thread.
307	    ///
308	    /// If this method is called from an [`unprotected`] guard, then the call will be just no-op.
309	    ///
310	    /// # Examples
311	    ///
312	    /// ```
313	    /// use crossbeam_epoch::{self as epoch, Atomic};
314	    /// use std::sync::atomic::Ordering::SeqCst;
315	    ///
316	    /// let a = Atomic::new(777);
317	    /// let mut guard = epoch::pin();
318	    /// {
319	    ///     let p = a.load(SeqCst, &guard);
320	    ///     assert_eq!(unsafe { p.as_ref() }, Some(&777));
321	    /// }
322	    /// guard.repin();
323	    /// {
324	    ///     let p = a.load(SeqCst, &guard);
325	    ///     assert_eq!(unsafe { p.as_ref() }, Some(&777));
326	    /// }
327	    /// # unsafe { drop(a.into_owned()); } // avoid leak
328	    /// ```
329	    pub fn repin(&mut self) {
330	        if let Some(local) = unsafe { self.local.as_ref() } {
331	            local.repin();
332	        }
333	    }
334	
335	    /// Temporarily unpins the thread, executes the given function and then re-pins the thread.
336	    ///
337	    /// This method is useful when you need to perform a long-running operation (e.g. sleeping)
338	    /// and don't need to maintain any guard-based reference across the call (the latter is enforced
339	    /// by `&mut self`). The thread will only be unpinned if this is the only active guard for the
340	    /// current thread.
341	    ///
342	    /// If this method is called from an [`unprotected`] guard, then the passed function is called
343	    /// directly without unpinning the thread.
344	    ///
345	    /// # Examples
346	    ///
347	    /// ```
348	    /// use crossbeam_epoch::{self as epoch, Atomic};
349	    /// use std::sync::atomic::Ordering::SeqCst;
350	    /// use std::thread;
351	    /// use std::time::Duration;
352	    ///
353	    /// let a = Atomic::new(777);
354	    /// let mut guard = epoch::pin();
355	    /// {
356	    ///     let p = a.load(SeqCst, &guard);
357	    ///     assert_eq!(unsafe { p.as_ref() }, Some(&777));
358	    /// }
359	    /// guard.repin_after(|| thread::sleep(Duration::from_millis(50)));
360	    /// {
361	    ///     let p = a.load(SeqCst, &guard);
362	    ///     assert_eq!(unsafe { p.as_ref() }, Some(&777));
363	    /// }
364	    /// # unsafe { drop(a.into_owned()); } // avoid leak
365	    /// ```
366	    pub fn repin_after<F, R>(&mut self, f: F) -> R
367	    where
368	        F: FnOnce() -> R,
369	    {
370	        // Ensure the Guard is re-pinned even if the function panics
371	        struct ScopeGuard(*const Local);
372	        impl Drop for ScopeGuard {
373	            fn drop(&mut self) {
374	                if let Some(local) = unsafe { self.0.as_ref() } {
375	                    mem::forget(local.pin());
376	                    unsafe {
377	                        Local::release_handle(local);
378	                    }
379	                }
380	            }
381	        }
382	
383	        if let Some(local) = unsafe { self.local.as_ref() } {
384	            // We need to acquire a handle here to ensure the Local doesn't
385	            // disappear from under us.
386	            local.acquire_handle();
387	            local.unpin();
388	        }
389	
390	        let _guard = ScopeGuard(self.local);
391	
392	        f()
393	    }
394	
395	    /// Returns the `Collector` associated with this guard.
396	    ///
397	    /// This method is useful when you need to ensure that all guards used with
398	    /// a data structure come from the same collector.
399	    ///
400	    /// If this method is called from an [`unprotected`] guard, then `None` is returned.
401	    ///
402	    /// # Examples
403	    ///
404	    /// ```
405	    /// use crossbeam_epoch as epoch;
406	    ///
407	    /// let guard1 = epoch::pin();
408	    /// let guard2 = epoch::pin();
409	    /// assert!(guard1.collector() == guard2.collector());
410	    /// ```
411	    pub fn collector(&self) -> Option<&Collector> {
412	        unsafe { self.local.as_ref().map(|local| local.collector()) }
413	    }
414	}
415	
416	impl Drop for Guard {
417	    #[inline]
418	    fn drop(&mut self) {
419	        if let Some(local) = unsafe { self.local.as_ref() } {
420	            local.unpin();
421	        }
422	    }
423	}
424	
425	impl fmt::Debug for Guard {
426	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
427	        f.pad("Guard { .. }")
428	    }
429	}
