431	/// Returns a reference to a dummy guard that allows unprotected access to [`Atomic`]s.
432	///
433	/// This guard should be used in special occasions only. Note that it doesn't actually keep any
434	/// thread pinned - it's just a fake guard that allows loading from [`Atomic`]s unsafely.
435	///
436	/// Note that calling [`defer`] with a dummy guard will not defer the function - it will just
437	/// execute the function immediately.
438	///
439	/// If necessary, it's possible to create more dummy guards by cloning: `unprotected().clone()`.
440	///
441	/// # Safety
442	///
443	/// Loading and dereferencing data from an [`Atomic`] using this guard is safe only if the
444	/// [`Atomic`] is not being concurrently modified by other threads.
445	///
446	/// # Examples
447	///
448	/// ```
449	/// use crossbeam_epoch::{self as epoch, Atomic};
450	/// use std::sync::atomic::Ordering::Relaxed;
451	///
452	/// let a = Atomic::new(7);
453	///
454	/// unsafe {
455	///     // Load `a` without pinning the current thread.
456	///     a.load(Relaxed, epoch::unprotected());
457	///
458	///     // It's possible to create more dummy guards.
459	///     let dummy = epoch::unprotected();
460	///
461	///     dummy.defer(move || {
462	///         println!("This gets executed immediately.");
463	///     });
464	///
465	///     // Dropping `dummy` doesn't affect the current thread - it's just a noop.
466	/// }
467	/// # unsafe { drop(a.into_owned()); } // avoid leak
468	/// ```
469	///
470	/// The most common use of this function is when constructing or destructing a data structure.
471	///
472	/// For example, we can use a dummy guard in the destructor of a Treiber stack because at that
473	/// point no other thread could concurrently modify the [`Atomic`]s we are accessing.
474	///
475	/// If we were to actually pin the current thread during destruction, that would just unnecessarily
476	/// delay garbage collection and incur some performance cost, so in cases like these `unprotected`
477	/// is very helpful.
478	///
479	/// ```
480	/// use crossbeam_epoch::{self as epoch, Atomic};
481	/// use std::mem::ManuallyDrop;
482	/// use std::sync::atomic::Ordering::Relaxed;
483	///
484	/// struct Stack<T> {
485	///     head: Atomic<Node<T>>,
486	/// }
487	///
488	/// struct Node<T> {
489	///     data: ManuallyDrop<T>,
490	///     next: Atomic<Node<T>>,
491	/// }
492	///
493	/// impl<T> Drop for Stack<T> {
494	///     fn drop(&mut self) {
495	///         unsafe {
496	///             // Unprotected load.
497	///             let mut node = self.head.load(Relaxed, epoch::unprotected());
498	///
499	///             while let Some(n) = node.as_ref() {
500	///                 // Unprotected load.
501	///                 let next = n.next.load(Relaxed, epoch::unprotected());
502	///
503	///                 // Take ownership of the node, then drop its data and deallocate it.
504	///                 let mut o = node.into_owned();
505	///                 ManuallyDrop::drop(&mut o.data);
506	///                 drop(o);
507	///
508	///                 node = next;
509	///             }
510	///         }
511	///     }
512	/// }
513	/// ```
514	///
515	/// [`Atomic`]: super::Atomic
516	/// [`defer`]: Guard::defer
517	#[inline]
518	pub unsafe fn unprotected() -> &'static Guard {
519	    // An unprotected guard is just a `Guard` with its field `local` set to null.
520	    // We make a newtype over `Guard` because `Guard` isn't `Sync`, so can't be directly stored in
521	    // a `static`
522	    struct GuardWrapper(Guard);
523	    unsafe impl Sync for GuardWrapper {}
524	    static UNPROTECTED: GuardWrapper = GuardWrapper(Guard {
525	        local: core::ptr::null(),
526	    });
527	    &UNPROTECTED.0
528	}
